import{_ as e,o as r,c as t,a0 as l}from"./chunks/framework.jwovEGr5.js";const f=JSON.parse('{"title":"Craft-Core 原味生存服官方文檔","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),i={name:"README.md"};function o(h,a,n,c,s,d){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="craft-core-原味生存服官方文檔" tabindex="-1">Craft-Core 原味生存服官方文檔 <a class="header-anchor" href="#craft-core-原味生存服官方文檔" aria-label="Permalink to &quot;Craft-Core 原味生存服官方文檔&quot;">​</a></h1><p>歡迎來到 <strong>Craft-Core 原味生存服</strong> 官方文檔！本指南將協助您快速熟悉本伺服器的箱子商店、領地防護、密碼安全箱，以及 Discord 機器人與網頁儀表板的使用方法。</p><hr><h2 id="🌐-系統三向連動設計" tabindex="-1">🌐 系統三向連動設計 <a class="header-anchor" href="#🌐-系統三向連動設計" aria-label="Permalink to &quot;🌐 系統三向連動設計&quot;">​</a></h2><p>本伺服器採用「遊戲內模組」、「Discord 聊天群組」與「網頁儀表板」三合一的即時互通系統，您的帳號金幣與資料會在這三個平台之間自動同步：</p><ul><li><strong>遊戲伺服器</strong>：進行箱子商店買賣、框選領地、密碼鎖設定與每日任務。</li><li><strong>Discord 機器人</strong>：進行每日簽到、福利抽獎、查看商店狀況與發送快遞。</li><li><strong>網頁儀表板</strong>：在網頁上直觀查看全服富豪排行榜、管理您的領地權限與密碼箱、閱讀實時交易廣播。</li></ul><hr><h2 id="🧭-文件導覽目錄" tabindex="-1">🧭 文件導覽目錄 <a class="header-anchor" href="#🧭-文件導覽目錄" aria-label="Permalink to &quot;🧭 文件導覽目錄&quot;">​</a></h2><p>您可以點選下方連結深入閱讀各單元的詳細教學：</p><h3 id="🖥️-1-網頁端儀表板使用指南" tabindex="-1">🖥️ 1. 網頁端儀表板使用指南 <a class="header-anchor" href="#🖥️-1-網頁端儀表板使用指南" aria-label="Permalink to &quot;🖥️ 1. 網頁端儀表板使用指南&quot;">​</a></h3><ul><li>🖥️ <a href="./Web-Dashboard.html">網頁版首頁簡介</a> — 首頁各項即時看板與帳號登入綁定。</li><li>🔍 <a href="./Web-Shop-Navigation.html">商店瀏覽與導航</a> — 搜尋全服擺攤並獲取快速傳送指令。</li><li>📈 <a href="./Web-Market-Analytics.html">全服市場行情</a> — 商品均價、7日價格走勢與系統回收機制。</li><li>📲 <a href="./Web-Owner-Remote.html">店主遠端遙控</a> — 網頁端遠端領取收益、修改招牌名稱與升級店面。</li><li>🛡️ <a href="./Web-Claims-Management.html">領地保護設定</a> — 網頁端設置好友的 Build、Break 等細部共建權限。</li><li>🔒 <a href="./Web-Password-Lock.html">密碼箱白名單管理</a> — 遠端管理密碼箱白名單授權、變更密碼與註銷。</li><li>🎁 <a href="./Web-Welfare.html">每日簽到與抽獎</a> — 網頁端簽到並消耗鑰匙參與福利抽獎。</li><li>📬 <a href="./Web-Postal-Inventory.html">郵局快遞與個人背包</a> — 即時預覽背包格、發送快遞包裹與金幣電子匯款。</li></ul><h3 id="🎮-2-minecraft-遊戲指南" tabindex="-1">🎮 2. Minecraft 遊戲指南 <a class="header-anchor" href="#🎮-2-minecraft-遊戲指南" aria-label="Permalink to &quot;🎮 2. Minecraft 遊戲指南&quot;">​</a></h3><ul><li>⚔️ <a href="./Mc-Task-System.html">每日任務系統</a> — 遊戲內擊殺與挖掘任務的玩法與領賞。</li><li>🏪 <a href="./Mc-Shop-System.html">商店系統概覽</a> — 玩家基礎買賣操作與商店更名升級。</li><li>🔨 <a href="./Mc-Create-Shop.html">如何新增商店</a> — 告示牌寫法規範與手持 <code>[this]</code> 自動建立技巧。</li><li>❌ <a href="./Mc-Delete-Shop.html">如何刪除商店</a> — 手動敲除與店主面板註銷商店方法。</li><li>🧭 <a href="./Mc-Teleport-Commands.html">遊戲內傳送與 TP 指令</a> — <code>/shop control</code>、<code>/home</code> 及 <code>/tpa</code> 等傳送快捷指令。</li><li>🛠️ <a href="./Mc-Admin-Management.html">管理員指令與權限</a> — 管理員無限商店、重新載入與全局強拆維護指令。</li></ul><h3 id="🤖-3-discord-機器人連動" tabindex="-1">🤖 3. Discord 機器人連動 <a class="header-anchor" href="#🤖-3-discord-機器人連動" aria-label="Permalink to &quot;🤖 3. Discord 機器人連動&quot;">​</a></h3><ul><li>🤖 <a href="./Discord-Integration.html">Discord 連動綁定</a> — 綁定 Minecraft 帳號、獲取每日簽到與大額營收成交廣播。</li></ul>',15)])])}const u=e(i,[["render",o]]);export{f as __pageData,u as default};
